#!/usr/bin/env node
// gen-registry.mjs — auto-discover features and write features/registry.generated.ts.
//
// A feature is a folder under features/ with an index.tsx that default-exports a
// `Feature` (see features/types.ts). This scanner finds every such folder and writes
// the registry automatically, so NO shared file is ever hand-edited — which means
// parallel feature PRs can never collide on a registry (no merge conflicts, ever).
//
// Runs from the package.json pre-hooks (predev / prebuild / pretypecheck / pretest),
// so the generated file always exists before Next/tsc/vitest compile. The output is
// git-ignored: it is rebuilt from the folders on disk, never committed.

import { readdirSync, statSync, existsSync, writeFileSync } from 'node:fs';
import { join, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

const root = join(dirname(fileURLToPath(import.meta.url)), '..');
const featuresDir = join(root, 'features');
const outFile = join(featuresDir, 'registry.generated.ts');

// camel-case the folder name for a valid import identifier: "theme-toggle" -> "themeToggle"
const toIdent = (name) => name.replace(/[-_]([a-z0-9])/g, (_, c) => c.toUpperCase());

const dirs = readdirSync(featuresDir)
  .filter((name) => {
    const p = join(featuresDir, name);
    return statSync(p).isDirectory() && existsSync(join(p, 'index.tsx'));
  })
  .sort();

const imports = dirs.map((d) => `import ${toIdent(d)} from './${d}';`).join('\n');
const entries = dirs.map((d) => `  ${toIdent(d)},`).join('\n');

const body = `// AUTO-GENERATED by scripts/gen-registry.mjs — DO NOT EDIT, DO NOT COMMIT.
// Rebuilt from the folders in features/ on every dev/build/typecheck/test run.
import type { Feature } from './types';
${imports}

export const features: Feature[] = [
${entries}
];
`;

writeFileSync(outFile, body);
console.log(`[gen-registry] ${dirs.length} feature(s): ${dirs.join(', ') || '(none)'}`);
